+import { NonExhaustiveError } from './errors';
+import { matchPattern } from './internals/helpers';
+import * as symbols from './internals/symbols';
+import type { MatchEach } from './types/MatchEach';
+
+type Clause = {
+  patterns?: readonly unknown[];
+  predicate: (value: unknown) => unknown;
+  handler: (selection: unknown, value: unknown) => unknown;
+};
+
+type Step = Clause | { tap: (result: unknown) => void };
+
+export function matchEach<const input, output = symbols.unset>(value: input): MatchEach<input, output>;
+export function matchEach<input, output = symbols.unset>(): MatchEach<input, output>;
+export function matchEach(...args: [unknown?]): any {
+  return new MatchEachExpression(args.length ? args[0] : undefined, args.length > 0, []);
+}
+
+class MatchEachExpression {
+  constructor(
+    private input: unknown,
+    private hasInput: boolean,
+    private steps: readonly Step[]
+  ) {}
+
+  with(...args: any[]): MatchEachExpression {
+    const handler = args[args.length - 1];
+    let patterns: unknown[] = [args[0]];
+    let predicate: (value: unknown) => unknown = () => true;
+    if (args.length === 3 && typeof args[1] === 'function') predicate = args[1];
+    else if (args.length > 2) patterns = args.slice(0, -1);
+    return this.add({ patterns, predicate, handler });
+  }
+
+  when(predicate: (value: unknown) => unknown, handler: (value: unknown) => unknown) {
+    return this.add({ predicate, handler });
+  }
+
+  tap(callback: (result: unknown) => void) {
+    return this.add({ tap: callback });
+  }
+
+  otherwise(handler: (value: unknown) => unknown): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [handler(this.input)];
+  }
+
+  exhaustive(fallback = defaultCatcher): unknown[] {
+    const results = this.evaluate(this.input);
+    return results.length ? results : [fallback(this.input)];
+  }
+
+  run(): unknown[] {
+    return this.exhaustive();
+  }
+
+  returnType() { return this; }
+
+  narrow() { return this; }
+
+  toFunction() {
+    return (input: unknown) => {
+      const results = this.evaluate(input);
+      if (!results.length) defaultCatcher(input);
+      return results;
+    };
+  }
+
+  toExhaustiveFunction() { return this.toFunction(); }
+
+  toPartialFunction() {
+    return (input: unknown) => {
+      const results = this.evaluate(input);
+      return results.length ? results : undefined;
+    };
+  }
+
+  private add(step: Step) {
+    return new MatchEachExpression(this.input, this.hasInput, [...this.steps, step]);
+  }
+
+  private evaluate(input: unknown): unknown[] {
+    const results: unknown[] = [];
+    for (const step of this.steps) {
+      if ('tap' in step) {
+        results.forEach(step.tap);
+        continue;
+      }
+      const selection = this.match(step, input);
+      if (selection.matched && step.predicate(input)) results.push(step.handler(selection.value, input));
+    }
+    return results;
+  }
+
+  private match(clause: Clause, input: unknown): { matched: boolean; value: unknown } {
+    if (!clause.patterns) return { matched: true, value: input };
+    for (const pattern of clause.patterns) {
+      let hasSelections = false;
+      const selected: Record<string, unknown> = {};
+      const matched = matchPattern(pattern, input, (key, value) => {
+        hasSelections = true;
+        selected[key] = value;
+      });
+      if (matched) {
+        return {
+          matched: true,
+          value: hasSelections
+            ? symbols.anonymousSelectKey in selected ? selected[symbols.anonymousSelectKey] : selected
+            : input,
+        };
+      }
+    }
+    return { matched: false, value: undefined };
+  }
+}
+
+function defaultCatcher(input: unknown): never {
+  throw new NonExhaustiveError(input);
